export interface MidiNote {
  pitch: number;
  startTime: number;
  duration: number;
  velocity: number;
  instrument?: string;
}

export interface TranscriptionResponse {
  notes: MidiNote[];
  bpm: number;
  timeSignature: string;
}

export enum PipelineStage {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  CONVERTING = 'CONVERTING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

export interface ChannelState {
  name: string;
  fader: number;
  pan: number;
  mute: boolean;
  solo: boolean;
  level: number;
}

import { MidiNote } from '../types';

/**
 * A minimal MIDI File builder
 * Generates a Standard MIDI File (SMF) Type 0
 */
export const buildMidiFile = (notes: MidiNote[], bpm: number = 120): Uint8Array => {
  const ticksPerBeat = 480;
  const tempo = Math.round(60000000 / bpm); // microseconds per beat

  // Header Chunk
  const header = [
    0x4d, 0x54, 0x68, 0x64, // "MThd"
    0x00, 0x00, 0x00, 0x06, // Length
    0x00, 0x00,             // Type 0
    0x00, 0x01,             // 1 track
    (ticksPerBeat >> 8) & 0xFF, ticksPerBeat & 0xFF
  ];

  const trackEvents: number[] = [];

  // Set Tempo Meta Event
  trackEvents.push(0x00, 0xFF, 0x51, 0x03, (tempo >> 16) & 0xFF, (tempo >> 8) & 0xFF, tempo & 0xFF);

  // Convert notes to sorted events (time, type, pitch, velocity)
  const events: { time: number; type: 'on' | 'off'; pitch: number; velocity: number }[] = [];
  notes.forEach(n => {
    events.push({ time: n.startTime, type: 'on', pitch: n.pitch, velocity: n.velocity });
    events.push({ time: n.startTime + n.duration, type: 'off', pitch: n.pitch, velocity: 0 });
  });

  events.sort((a, b) => a.time - b.time);

  let lastTick = 0;
  events.forEach(e => {
    const currentTick = Math.round(e.time * bpm * ticksPerBeat / 60);
    const delta = currentTick - lastTick;
    lastTick = currentTick;

    // Write Delta Time as Variable Length Quantity
    writeVarLen(trackEvents, delta);

    // Write Event
    if (e.type === 'on') {
      trackEvents.push(0x90, e.pitch, e.velocity);
    } else {
      trackEvents.push(0x80, e.pitch, 0x00);
    }
  });

  // End of track
  trackEvents.push(0x00, 0xFF, 0x2F, 0x00);

  const trackHeader = [
    0x4d, 0x54, 0x72, 0x6b, // "MTrk"
    (trackEvents.length >> 24) & 0xFF,
    (trackEvents.length >> 16) & 0xFF,
    (trackEvents.length >> 8) & 0xFF,
    trackEvents.length & 0xFF
  ];

  return new Uint8Array([...header, ...trackHeader, ...trackEvents]);
};

function writeVarLen(arr: number[], value: number) {
  let buffer = value & 0x7F;
  while ((value >>= 7) > 0) {
    buffer <<= 8;
    buffer |= 0x80;
    buffer |= (value & 0x7F);
  }
  while (true) {
    arr.push(buffer & 0xFF);
    if (buffer & 0x80) buffer >>= 8;
    else break;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { TranscriptionResponse } from "../types";

const API_KEY = process.env.API_KEY || '';

export const transcribeAudio = async (base64Data: string, mimeType: string): Promise<TranscriptionResponse> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    Transcribe this audio file into precise MIDI note data.
    Identify the main instruments (drums, bass, or melody).
    Focus specifically on rhythmic accuracy.

    Return the data as a JSON object with:
    - bpm: estimated beats per minute
    - timeSignature: e.g. "4/4"
    - notes: an array of objects with { pitch, startTime, duration, velocity }.

    Pitch should be a MIDI number (0-127).
    startTime and duration should be in seconds.
    velocity should be 0-127.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            bpm: { type: Type.NUMBER },
            timeSignature: { type: Type.STRING },
            notes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  pitch: { type: Type.NUMBER },
                  startTime: { type: Type.NUMBER },
                  duration: { type: Type.NUMBER },
                  velocity: { type: Type.NUMBER }
                },
                required: ["pitch", "startTime", "duration", "velocity"]
              }
            }
          },
          required: ["bpm", "timeSignature", "notes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as TranscriptionResponse;
  } catch (error) {
    console.error("Gemini Transcription Error:", error);
    throw error;
  }
};

import React from 'react';
import { ChannelState } from '../types';

interface MixerProps {
  channels: ChannelState[];
  setChannels: React.Dispatch<React.SetStateAction<ChannelState[]>>;
}

export const Mixer: React.FC<MixerProps> = ({ channels, setChannels }) => {
  const updateChannel = (index: number, updates: Partial<ChannelState>) => {
    setChannels(prev => prev.map((ch, i) => i === index ? { ...ch, ...updates } : ch));
  };

  return (
    <div className="flex gap-4 p-6 bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl overflow-x-auto shadow-2xl">
      {channels.map((ch, i) => (
        <div key={ch.name} className="flex flex-col items-center gap-4 w-20 flex-shrink-0 bg-gradient-to-b from-[#111] to-[#080808] p-3 rounded-lg border border-[#222]">
          <span className="mono text-[10px] font-bold text-cyan-400 tracking-widest uppercase">{ch.name}</span>

          <div className="flex gap-1 h-32 w-10 bg-[#050505] rounded p-1 border border-[#111] items-end justify-center">
            {Array.from({ length: 15 }).map((_, b) => {
              const active = ch.level > (b / 15);
              return (
                <div 
                  key={b} 
                  className={`w-full h-[6px] rounded-sm transition-colors duration-75 ${
                    active 
                      ? b > 12 ? 'bg-red-500' : b > 10 ? 'bg-yellow-400' : 'bg-cyan-500' 
                      : 'bg-[#1a1a1a]'
                  }`} 
                />
              );
            })}
          </div>

          <div className="flex flex-col gap-2 w-full">
             <button 
              onClick={() => updateChannel(i, { mute: !ch.mute })}
              className={`text-[9px] font-bold py-1 rounded transition-all ${ch.mute ? 'bg-red-600 text-white shadow-[0_0_10px_rgba(220,38,38,0.4)]' : 'bg-[#222] text-gray-500'}`}
            >
              MUTE
            </button>
            <button 
              onClick={() => updateChannel(i, { solo: !ch.solo })}
              className={`text-[9px] font-bold py-1 rounded transition-all ${ch.solo ? 'bg-orange-500 text-black shadow-[0_0_10px_rgba(249,115,22,0.4)]' : 'bg-[#222] text-gray-500'}`}
            >
              SOLO
            </button>
          </div>

          <div className="relative h-40 w-8 flex justify-center cursor-ns-resize bg-[#050505] rounded-full border border-[#111]">
             <input 
              type="range" 
              min="0" 
              max="1" 
              step="0.01" 
              value={ch.fader} 
              onChange={(e) => updateChannel(i, { fader: parseFloat(e.target.value) })}
              className="absolute inset-0 opacity-0 cursor-pointer h-full w-full"
              style={{ writingMode: 'bt-lr' } as any}
            />
            <div 
              className="absolute pointer-events-none w-6 h-10 bg-gradient-to-b from-[#444] to-[#222] rounded shadow-lg border border-[#555]"
              style={{ bottom: `${ch.fader * 100}%`, transform: 'translateY(50%)' }}
            >
               <div className="w-full h-1 bg-cyan-400 mt-4 shadow-[0_0_5px_#22d3ee]" />
            </div>
          </div>

          <span className="mono text-[10px] text-gray-600">{(ch.fader * 10).toFixed(1)} dB</span>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Upload, Music, Download, Layers, Activity, AlertCircle, Play, Square } from 'lucide-react';
import { PipelineStage, ChannelState, TranscriptionResponse } from './types';
import { transcribeAudio } from './services/geminiService';
import { buildMidiFile } from './utils/midiBuilder';
import { Mixer } from './components/Mixer';

const App: React.FC = () => {
  const [stage, setStage] = useState<PipelineStage>(PipelineStage.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [transcription, setTranscription] = useState<TranscriptionResponse | null>(null);
  const [channels, setChannels] = useState<ChannelState[]>([
    { name: 'KICK', fader: 0.8, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'SNARE', fader: 0.7, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'HAT', fader: 0.6, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'PERC', fader: 0.5, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'BASS', fader: 0.7, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'SYNTH', fader: 0.6, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'MASTER', fader: 0.9, pan: 0.5, mute: false, solo: false, level: 0 },
  ]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [fileName, setFileName] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Meter simulation loop
  useEffect(() => {
    const interval = setInterval(() => {
      setChannels(prev => prev.map(ch => {
        if (!isPlaying || ch.mute) return { ...ch, level: 0 };
        return { ...ch, level: Math.random() * ch.fader };
      }));
    }, 100);
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.type.includes('audio/wav') && !file.type.includes('audio/mpeg') && !file.type.includes('audio/x-wav')) {
      setError("Please upload a valid WAV or MP3 file.");
      return;
    }

    setFileName(file.name);
    setStage(PipelineStage.UPLOADING);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        setStage(PipelineStage.ANALYZING);

        const result = await transcribeAudio(base64, file.type);
        setTranscription(result);
        setStage(PipelineStage.COMPLETE);
      };
      reader.readAsDataURL(file);
    } catch (err: any) {
      setError(err.message || "Transcription failed. Please try again.");
      setStage(PipelineStage.ERROR);
    }
  };

  const downloadMidi = () => {
    if (!transcription) return;
    const midiBytes = buildMidiFile(transcription.notes, transcription.bpm);
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName?.split('.')[0] || 'transcription'}.mid`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center bg-[#050505] selection:bg-cyan-500/30">
      {/* Header Section */}
      <header className="w-full max-w-6xl flex justify-between items-end mb-12 border-b border-[#1a1a1a] pb-6">
        <div>
          <h1 className="text-4xl font-extrabold tracking-tighter text-white flex items-center gap-3">
            <span className="bg-cyan-600 text-black px-2 py-0.5 rounded italic">BW</span>
            WAV2MIDI STUDIO
          </h1>
          <p className="mono text-[10px] text-gray-500 tracking-[0.3em] mt-2 uppercase">
            AI-Powered Neural Transcription Engine v2.5
          </p>
        </div>
        <div className="hidden md:flex flex-col items-end mono text-[10px] text-cyan-400/50 space-y-1">
          <span>LATENCY: 42ms</span>
          <span>GPU_ACCEL: ACTIVE</span>
          <span>ENGINE_STATUS: OPTIMAL</span>
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Upload & Stage Control */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl">
            <h2 className="text-sm font-bold text-gray-400 mb-4 flex items-center gap-2 uppercase tracking-widest">
              <Upload size={14} /> Source Audio
            </h2>

            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`group relative h-48 border-2 border-dashed rounded-lg flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                ${stage === PipelineStage.IDLE ? 'border-[#222] hover:border-cyan-500/50 hover:bg-cyan-500/5' : 'border-cyan-500/20 bg-cyan-500/5'}
              `}
            >
              {stage === PipelineStage.IDLE ? (
                <>
                  <Upload className="text-gray-600 group-hover:text-cyan-400 transition-colors mb-3" size={32} />
                  <span className="text-xs font-bold text-gray-500 group-hover:text-cyan-400 transition-colors uppercase">Drop WAV Here</span>
                  <span className="text-[10px] text-gray-700 mt-1 uppercase mono">Stereo / 44.1kHz</span>
                </>
              ) : (
                <div className="flex flex-col items-center animate-pulse">
                  <Activity className="text-cyan-400 mb-3" size={32} />
                  <span className="text-xs font-bold text-cyan-400 uppercase tracking-widest">{stage}</span>
                </div>
              )}
              <input 
                ref={fileInputRef}
                type="file" 
                className="hidden" 
                onChange={handleFileUpload}
                accept=".wav,.mp3,.wave"
              />
            </div>

            {fileName && (
              <div className="mt-4 p-3 bg-black/40 rounded border border-[#1a1a1a] flex items-center justify-between">
                <div className="flex items-center gap-3 overflow-hidden">
                  <Music size={16} className="text-cyan-500 flex-shrink-0" />
                  <span className="text-[11px] truncate text-gray-400 mono">{fileName}</span>
                </div>
                <button 
                  onClick={() => setIsPlaying(!isPlaying)}
                  className="p-2 bg-[#1a1a1a] hover:bg-[#222] rounded-full text-cyan-400 transition-colors"
                >
                  {isPlaying ? <Square size={14} fill="currentColor" /> : <Play size={14} fill="currentColor" />}
                </button>
              </div>
            )}
          </div>

          {/* Status Display */}
          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl">
             <h2 className="text-sm font-bold text-gray-400 mb-4 flex items-center gap-2 uppercase tracking-widest">
              <Layers size={14} /> Intelligence Pipeline
            </h2>
            <div className="space-y-4">
              {[
                { name: 'Audio Pre-processing', active: stage !== PipelineStage.IDLE },
                { name: 'Drum/Voice Separation', active: [PipelineStage.ANALYZING, PipelineStage.CONVERTING, PipelineStage.COMPLETE].includes(stage) },
                { name: 'MIDI Feature Extraction', active: [PipelineStage.ANALYZING, PipelineStage.CONVERTING, PipelineStage.COMPLETE].includes(stage) },
                { name: 'Neural Reconstruction', active: [PipelineStage.COMPLETE].includes(stage) },
              ].map((s, idx) => (
                <div key={idx} className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${s.active ? 'bg-cyan-500 shadow-[0_0_8px_#22d3ee]' : 'bg-[#222]'}`} />
                  <span className={`text-[11px] mono uppercase tracking-wider ${s.active ? 'text-gray-300' : 'text-gray-700'}`}>{s.name}</span>
                </div>
              ))}
            </div>
          </div>

          {error && (
            <div className="bg-red-950/20 border border-red-900/50 rounded-xl p-4 flex items-start gap-3">
              <AlertCircle className="text-red-500 mt-0.5" size={16} />
              <div className="flex flex-col">
                <span className="text-xs font-bold text-red-400 uppercase tracking-wider">Engine Fault</span>
                <span className="text-[10px] text-red-300/70 mono leading-relaxed mt-1">{error}</span>
              </div>
            </div>
          )}
        </div>

        {/* Right Column: Visualizer & Mixer */}
        <div className="lg:col-span-2 space-y-6">
          {/* Piano Roll / Result Section */}
          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl h-[400px] flex flex-col">
             <div className="flex justify-between items-center mb-6">
               <h2 className="text-sm font-bold text-gray-400 flex items-center gap-2 uppercase tracking-widest">
                <Activity size={14} /> Piano Roll Analysis
              </h2>
              {transcription && (
                <div className="flex items-center gap-4">
                  <div className="flex flex-col items-end px-4 border-r border-[#1a1a1a]">
                    <span className="mono text-[10px] text-gray-600">BPM</span>
                    <span className="mono text-lg font-bold text-cyan-400 leading-none">{transcription.bpm}</span>
                  </div>
                   <button 
                    onClick={downloadMidi}
                    className="flex items-center gap-2 px-4 py-2 bg-cyan-600 hover:bg-cyan-500 text-black font-bold text-xs rounded transition-all shadow-lg hover:shadow-cyan-500/20 active:scale-95"
                  >
                    <Download size={14} /> EXPORT MIDI
                  </button>
                </div>
              )}
             </div>

             <div className="flex-grow bg-[#050505] rounded-lg border border-[#1a1a1a] relative overflow-hidden group">
               {/* Piano Roll Mockup Grid */}
               <div className="absolute inset-0 opacity-10" 
                 style={{ 
                   backgroundImage: 'linear-gradient(#222 1px, transparent 1px), linear-gradient(90deg, #222 1px, transparent 1px)',
                   backgroundSize: '40px 10px' 
                 }} 
               />

               {transcription ? (
                 <div className="absolute inset-0 p-4">
                   {transcription.notes.slice(0, 40).map((note, i) => (
                     <div 
                        key={i}
                        className="absolute h-1.5 rounded-full bg-cyan-500/80 shadow-[0_0_8px_rgba(34,211,238,0.5)] animate-in fade-in slide-in-from-left duration-500"
                        style={{
                          left: `${(note.startTime % 10) * 10}%`,
                          top: `${(1 - (note.pitch - 21) / 88) * 100}%`,
                          width: `${note.duration * 40}px`,
                        }}
                     />
                   ))}
                 </div>
               ) : (
                 <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8 opacity-20">
                    <Music size={48} className="mb-4" />
                    <p className="mono text-xs uppercase tracking-widest">Neural transcription results will manifest here</p>
                 </div>
               )}
             </div>
          </div>

          {/* Mixer Component */}
          <Mixer channels={channels} setChannels={setChannels} />
        </div>
      </main>

      <footer className="mt-12 w-full max-w-6xl flex justify-between items-center py-6 border-t border-[#1a1a1a] mono text-[10px] text-gray-700 tracking-widest">
        <span>&copy; 2024 BUILDWHILEBLEEDING DIGITAL INSTRUMENTS</span>
        <div className="flex gap-6">
          <span className="hover:text-cyan-400 cursor-pointer transition-colors">VIRTUAL_ANALOG_CORE</span>
          <span className="hover:text-cyan-400 cursor-pointer transition-colors">STABILITY_PATCH: 0.9.1</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Upload, Music, Download, Layers, Activity, AlertCircle, Play, Square, Volume2 } from 'lucide-react';
import { PipelineStage, ChannelState, TranscriptionResponse, MidiNote } from './types';
import { transcribeAudio } from './services/geminiService';
import { buildMidiFile } from './utils/midiBuilder';
import { Mixer } from './components/Mixer';

const App: React.FC = () => {
  const [stage, setStage] = useState<PipelineStage>(PipelineStage.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [transcription, setTranscription] = useState<TranscriptionResponse | null>(null);
  const [channels, setChannels] = useState<ChannelState[]>([
    { name: 'KICK', fader: 0.8, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'SNARE', fader: 0.7, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'HAT', fader: 0.6, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'PERC', fader: 0.5, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'BASS', fader: 0.7, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'SYNTH', fader: 0.6, pan: 0.5, mute: false, solo: false, level: 0 },
    { name: 'MASTER', fader: 0.8, pan: 0.5, mute: false, solo: false, level: 0 },
  ]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [fileName, setFileName] = useState<string | null>(null);
  const [playbackTime, setPlaybackTime] = useState(0);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const requestRef = useRef<number>(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Synth preview refs
  const activeOscillators = useRef<Map<number, { osc: OscillatorNode, gain: GainNode }>>(new Map());

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      cancelAnimationFrame(requestRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  // Meter & Time update loop
  const updateMeters = useCallback(() => {
    if (!analyserRef.current || !isPlaying) {
      requestRef.current = requestAnimationFrame(updateMeters);
      return;
    }

    const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Simple average for master level
    const sum = dataArray.reduce((a, b) => a + b, 0);
    const average = (sum / dataArray.length) / 255;

    // Update time
    if (audioContextRef.current) {
      setPlaybackTime(audioContextRef.current.currentTime - startTimeRef.current);
    }

    setChannels(prev => prev.map(ch => {
      if (ch.name === 'MASTER') return { ...ch, level: average * ch.fader * 1.5 };
      // Map other channels to frequency ranges for visual flair
      const rangeMap: Record<string, [number, number]> = {
        'KICK': [0, 5], 'SNARE': [10, 30], 'HAT': [100, 200], 'PERC': [40, 80], 'BASS': [5, 15], 'SYNTH': [20, 100]
      };
      const range = rangeMap[ch.name] || [0, 1];
      const slice = dataArray.slice(range[0], range[1]);
      const sliceAvg = slice.reduce((a, b) => a + b, 0) / (slice.length || 1) / 255;
      return { ...ch, level: sliceAvg * ch.fader * 2 };
    }));

    requestRef.current = requestAnimationFrame(updateMeters);
  }, [isPlaying]);

  useEffect(() => {
    requestRef.current = requestAnimationFrame(updateMeters);
    return () => cancelAnimationFrame(requestRef.current);
  }, [updateMeters]);

  // Handle Mixer Fader changes
  useEffect(() => {
    if (gainNodeRef.current) {
      const master = channels.find(c => c.name === 'MASTER');
      if (master) {
        gainNodeRef.current.gain.setValueAtTime(master.fader, audioContextRef.current?.currentTime || 0);
      }
    }
  }, [channels]);

  const initAudio = async (arrayBuffer: ArrayBuffer) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const buffer = await audioContextRef.current.decodeAudioData(arrayBuffer);
    audioBufferRef.current = buffer;

    // Setup Graph
    analyserRef.current = audioContextRef.current.createAnalyser();
    analyserRef.current.fftSize = 256;
    gainNodeRef.current = audioContextRef.current.createGain();

    const master = channels.find(c => c.name === 'MASTER');
    gainNodeRef.current.gain.value = master?.fader || 1;

    gainNodeRef.current.connect(analyserRef.current);
    analyserRef.current.connect(audioContextRef.current.destination);
  };

  const playSynthNote = (pitch: number, velocity: number) => {
    if (!audioContextRef.current || !gainNodeRef.current) return;
    const ctx = audioContextRef.current;

    const osc = ctx.createOscillator();
    const g = ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(440 * Math.pow(2, (pitch - 69) / 12), ctx.currentTime);

    g.gain.setValueAtTime(0, ctx.currentTime);
    g.gain.linearRampToValueAtTime((velocity / 127) * 0.1, ctx.currentTime + 0.01);

    osc.connect(g);
    g.connect(gainNodeRef.current);

    osc.start();
    return { osc, g };
  };

  const togglePlayback = () => {
    if (!audioContextRef.current || !audioBufferRef.current) return;

    if (isPlaying) {
      sourceNodeRef.current?.stop();
      setIsPlaying(false);
    } else {
      sourceNodeRef.current = audioContextRef.current.createBufferSource();
      sourceNodeRef.current.buffer = audioBufferRef.current;
      sourceNodeRef.current.connect(gainNodeRef.current!);

      startTimeRef.current = audioContextRef.current.currentTime;
      sourceNodeRef.current.start(0);
      sourceNodeRef.current.onended = () => setIsPlaying(false);
      setIsPlaying(true);
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStage(PipelineStage.UPLOADING);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const arrayBuffer = reader.result as ArrayBuffer;
        await initAudio(arrayBuffer);

        // Convert to base64 for Gemini
        const blob = new Blob([arrayBuffer], { type: file.type });
        const b64Reader = new FileReader();
        b64Reader.onload = async () => {
          const base64 = (b64Reader.result as string).split(',')[1];
          setStage(PipelineStage.ANALYZING);
          const result = await transcribeAudio(base64, file.type);
          setTranscription(result);
          setStage(PipelineStage.COMPLETE);
        };
        b64Reader.readAsDataURL(blob);
      };
      reader.readAsArrayBuffer(file);
    } catch (err: any) {
      setError(err.message || "Engine failure during transcription.");
      setStage(PipelineStage.ERROR);
    }
  };

  const downloadMidi = () => {
    if (!transcription) return;
    const midiBytes = buildMidiFile(transcription.notes, transcription.bpm);
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName?.split('.')[0] || 'session'}.mid`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center bg-[#050505] selection:bg-cyan-500/30">
      <header className="w-full max-w-6xl flex justify-between items-end mb-12 border-b border-[#1a1a1a] pb-6">
        <div>
          <h1 className="text-4xl font-extrabold tracking-tighter text-white flex items-center gap-3">
            <span className="bg-cyan-600 text-black px-2 py-0.5 rounded italic">BW</span>
            WAV2MIDI STUDIO
          </h1>
          <p className="mono text-[10px] text-gray-500 tracking-[0.3em] mt-2 uppercase">
            Neural Transcription Engine <span className="text-cyan-500/50">v2.5.8-STABLE</span>
          </p>
        </div>
        <div className="hidden md:flex flex-col items-end mono text-[10px] text-cyan-400/50 space-y-1">
          <span>SAMPLERATE: {audioContextRef.current?.sampleRate || 44100}Hz</span>
          <span>GPU_ACCEL: {stage === PipelineStage.ANALYZING ? 'STRESS' : 'IDLE'}</span>
          <span>ENGINE_STATUS: {stage === PipelineStage.ERROR ? 'FAILED' : 'READY'}</span>
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl relative overflow-hidden">
             <div className="absolute top-0 right-0 p-2">
                <div className={`w-2 h-2 rounded-full ${isPlaying ? 'bg-red-500 animate-pulse' : 'bg-gray-800'}`} />
             </div>
            <h2 className="text-sm font-bold text-gray-400 mb-4 flex items-center gap-2 uppercase tracking-widest">
              <Upload size={14} /> Source Deck
            </h2>

            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`group relative h-48 border-2 border-dashed rounded-lg flex flex-col items-center justify-center transition-all cursor-pointer overflow-hidden
                ${stage === PipelineStage.IDLE ? 'border-[#222] hover:border-cyan-500/50 hover:bg-cyan-500/5' : 'border-cyan-500/20 bg-cyan-500/5'}
              `}
            >
              {stage === PipelineStage.IDLE ? (
                <>
                  <Upload className="text-gray-600 group-hover:text-cyan-400 transition-colors mb-3" size={32} />
                  <span className="text-xs font-bold text-gray-500 group-hover:text-cyan-400 transition-colors uppercase">Ingest Audio</span>
                  <span className="text-[10px] text-gray-700 mt-1 uppercase mono">PCM / MP3 / AIFF</span>
                </>
              ) : (
                <div className="flex flex-col items-center">
                  <Activity className="text-cyan-400 mb-3 animate-bounce" size={32} />
                  <span className="text-xs font-bold text-cyan-400 uppercase tracking-widest">{stage}</span>
                </div>
              )}
              <input 
                ref={fileInputRef}
                type="file" 
                className="hidden" 
                onChange={handleFileUpload}
                accept=".wav,.mp3,.wave,.aiff"
              />
            </div>

            {fileName && (
              <div className="mt-4 p-3 bg-black/40 rounded border border-[#1a1a1a] flex items-center justify-between">
                <div className="flex flex-col overflow-hidden">
                  <div className="flex items-center gap-2">
                    <Music size={14} className="text-cyan-500 flex-shrink-0" />
                    <span className="text-[11px] truncate text-gray-300 mono font-bold">{fileName}</span>
                  </div>
                  <span className="text-[9px] text-gray-600 mono mt-1">
                    {Math.floor(playbackTime / 60)}:{(playbackTime % 60).toFixed(0).padStart(2, '0')} / 
                    {audioBufferRef.current ? ` ${Math.floor(audioBufferRef.current.duration / 60)}:${(audioBufferRef.current.duration % 60).toFixed(0).padStart(2, '0')}` : ' --:--'}
                  </span>
                </div>
                <button 
                  onClick={togglePlayback}
                  disabled={stage === PipelineStage.ANALYZING}
                  className={`p-3 rounded-full transition-all shadow-lg ${isPlaying ? 'bg-red-600 text-white' : 'bg-cyan-600 text-black hover:scale-105 active:scale-95'}`}
                >
                  {isPlaying ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" className="ml-0.5" />}
                </button>
              </div>
            )}
          </div>

          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl">
             <h2 className="text-sm font-bold text-gray-400 mb-4 flex items-center gap-2 uppercase tracking-widest">
              <Layers size={14} /> Processing Log
            </h2>
            <div className="space-y-4">
              {[
                { name: 'Fast Fourier Transform', active: !!audioBufferRef.current },
                { name: 'Transient Detection', active: stage === PipelineStage.ANALYZING || stage === PipelineStage.COMPLETE },
                { name: 'Harmonic Mapping', active: stage === PipelineStage.COMPLETE },
                { name: 'MIDI Serialization', active: stage === PipelineStage.COMPLETE },
              ].map((s, idx) => (
                <div key={idx} className="flex items-center gap-3">
                  <div className={`w-1.5 h-1.5 rounded-full ${s.active ? 'bg-cyan-500 shadow-[0_0_8px_#22d3ee]' : 'bg-[#222]'}`} />
                  <span className={`text-[10px] mono uppercase tracking-widest ${s.active ? 'text-gray-300' : 'text-gray-700'}`}>{s.name}</span>
                  {s.active && idx === 1 && stage === PipelineStage.ANALYZING && <span className="text-[9px] text-cyan-600 animate-pulse ml-auto">RUNNING...</span>}
                </div>
              ))}
            </div>
          </div>

          {error && (
            <div className="bg-red-950/20 border border-red-900/50 rounded-xl p-4 flex items-start gap-3">
              <AlertCircle className="text-red-500 mt-0.5" size={16} />
              <div className="flex flex-col">
                <span className="text-xs font-bold text-red-400 uppercase tracking-wider">Kernel Panic</span>
                <span className="text-[10px] text-red-300/70 mono leading-relaxed mt-1">{error}</span>
              </div>
            </div>
          )}
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="bg-[#0a0a0a] border border-[#1a1a1a] rounded-xl p-6 shadow-xl h-[400px] flex flex-col relative">
             <div className="flex justify-between items-center mb-6">
               <h2 className="text-sm font-bold text-gray-400 flex items-center gap-2 uppercase tracking-widest">
                <Activity size={14} /> Matrix Preview
              </h2>
              {transcription && (
                <div className="flex items-center gap-4 animate-in fade-in zoom-in duration-500">
                  <div className="flex flex-col items-end px-4 border-r border-[#1a1a1a]">
                    <span className="mono text-[10px] text-gray-600">PROJECT BPM</span>
                    <span className="mono text-lg font-bold text-cyan-400 leading-none">{transcription.bpm}</span>
                  </div>
                   <button 
                    onClick={downloadMidi}
                    className="flex items-center gap-2 px-6 py-2.5 bg-cyan-600 hover:bg-cyan-500 text-black font-bold text-xs rounded shadow-lg hover:shadow-cyan-500/40 active:scale-95 transition-all"
                  >
                    <Download size={14} /> EXPORT .MID
                  </button>
                </div>
              )}
             </div>

             <div className="flex-grow bg-[#050505] rounded-lg border border-[#1a1a1a] relative overflow-hidden group">
               <div className="absolute inset-0 opacity-20 pointer-events-none" 
                 style={{ 
                   backgroundImage: 'linear-gradient(#222 1px, transparent 1px), linear-gradient(90deg, #222 1px, transparent 1px)',
                   backgroundSize: '40px 12px' 
                 }} 
               />

               {transcription ? (
                 <div 
                   className="absolute inset-0 p-4 transition-transform duration-100 ease-linear"
                   style={{ transform: `translateX(-${(playbackTime / 10) * 100}%)` }}
                 >
                   {transcription.notes.map((note, i) => {
                     const isPlayingNow = isPlaying && playbackTime >= note.startTime && playbackTime <= note.startTime + note.duration;
                     return (
                       <div 
                          key={i}
                          className={`absolute h-2 rounded-sm transition-all duration-300 ${isPlayingNow ? 'bg-white shadow-[0_0_15px_#fff] z-10' : 'bg-cyan-500/40'}`}
                          style={{
                            left: `${note.startTime * 100}px`,
                            top: `${(1 - (note.pitch - 21) / 88) * 100}%`,
                            width: `${note.duration * 100}px`,
                          }}
                       />
                     );
                   })}
                 </div>
               ) : (
                 <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8 opacity-10">
                    <Layers size={64} className="mb-4 text-gray-400" />
                    <p className="mono text-xs uppercase tracking-[0.3em]">Grid awaiting sequence data</p>
                 </div>
               )}

               {/* Playback Head */}
               {isPlaying && (
                 <div className="absolute top-0 bottom-0 left-1/2 w-px bg-red-500/50 shadow-[0_0_10px_red] z-20 pointer-events-none">
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-2 h-2 bg-red-500 rotate-45" />
                 </div>
               )}
             </div>

             <div className="mt-4 flex justify-between items-center mono text-[9px] text-gray-600">
               <span>PITCH [A0 - C8]</span>
               <span className="text-cyan-500/40">SCROLL LOCK: OFF</span>
               <span>TIME [SEC]</span>
             </div>
          </div>

          <Mixer channels={channels} setChannels={setChannels} />
        </div>
      </main>

      <footer className="mt-12 w-full max-w-6xl flex justify-between items-center py-6 border-t border-[#1a1a1a] mono text-[10px] text-gray-700 tracking-widest">
        <div className="flex items-center gap-2">
           <Volume2 size={12} className="text-cyan-500" />
           <span>&copy; 2025 BUILDWHILE DIGITAL INSTRUMENTS</span>
        </div>
        <div className="flex gap-6">
          <span className="hover:text-cyan-400 cursor-pointer transition-colors">VIRTUAL_SYNTH_PREVIEW: ACTIVE</span>
          <span className="hover:text-cyan-400 cursor-pointer transition-colors">IO_BUFFER: 512</span>
        </div>
      </footer>
    </div>
  );
};

