import React, { useState, useEffect, useRef } from 'react';
import { 
  Activity, 
  Upload, 
  Zap, 
  Power,
  Disc,
  Drum,
  Target,
  Settings,
  Waves,
  Mic2,
  Music,
  Activity as BassIcon
} from 'lucide-react';

// --- VISUALIZATION ENGINE ---

const useImpactOscilloscope = (canvasRef, active, color, mode = 'waveform') => {
  const animationRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    let phase = 0;
    const render = () => {
      ctx.fillStyle = '#0a0a0c';
      ctx.fillRect(0, 0, rect.width, rect.height);

      ctx.strokeStyle = '#1a1a1e';
      ctx.lineWidth = 1;
      for (let y = 0; y < rect.height; y += 4) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(rect.width, y); ctx.stroke();
      }

      if (active) {
        ctx.beginPath();
        ctx.lineWidth = 2;
        ctx.strokeStyle = color;
        ctx.shadowBlur = 12;
        ctx.shadowColor = color;

        const midY = rect.height / 2;
        ctx.moveTo(0, midY);

        if (mode === 'drums') {
          for (let x = 0; x < rect.width; x++) {
            const spike = Math.pow(Math.sin(x * 0.08 - phase), 12) * (rect.height * 0.45);
            ctx.lineTo(x, midY - spike + (Math.random() - 0.5) * 4);
          }
        } else {
          for (let x = 0; x < rect.width; x++) {
            const y = midY + Math.sin(x * 0.04 + phase) * 15 + Math.sin(x * 0.1) * 5;
            ctx.lineTo(x, y);
          }
        }
        ctx.stroke();
        ctx.shadowBlur = 0;
        phase += 0.25;
      }
      animationRef.current = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationRef.current);
  }, [canvasRef, active, color, mode]);
};

// --- COMPONENT PRIMITIVES ---

const LargeKnob = ({ label, value, onChange, min = 0, max = 10.0, suffix = "dB" }) => {
  const rotation = (value / max) * 270 - 135;
  return (
    <div className="flex flex-col items-center gap-4">
      <div className="relative w-40 h-40 rounded-full bg-gradient-to-b from-zinc-700 to-zinc-900 p-1 shadow-[0_10px_30px_rgba(0,0,0,0.8),inset_0_2px_5px_rgba(255,255,255,0.1)]">
        <div className="w-full h-full rounded-full bg-[#121214] border-4 border-zinc-800 flex items-center justify-center relative overflow-hidden">
          <div 
            className="absolute inset-0 border-[6px] border-cyan-500/20 rounded-full"
            style={{ clipPath: `conic-gradient(from 225deg, #06b6d4 ${(value/max)*75}%, transparent 0)` }}
          />
          <div 
            className="w-2 h-12 bg-cyan-500 absolute top-4 rounded-full shadow-[0_0_15px_#06b6d4] transition-transform duration-75"
            style={{ transform: `rotate(${rotation}deg)`, transformOrigin: 'bottom center' }}
          />
          <div className="text-center z-10">
            <div className="text-xl font-mono text-zinc-300 font-bold">{value.toFixed(1)} <span className="text-[10px] text-zinc-500">{suffix}</span></div>
            <div className="text-[9px] font-black tracking-widest text-zinc-600 uppercase mt-1">AMOUNT</div>
          </div>
        </div>
        <input 
          type="range" min={min} max={max} step="0.1" value={value} onChange={(e) => onChange(parseFloat(e.target.value))}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        />
      </div>
      <div className="text-xs font-black tracking-[0.3em] text-zinc-500 uppercase">{label}</div>
    </div>
  );
};

const ProFader = ({ label, value, onChange, color = "cyan" }) => {
  const height = value * 100;
  const glow = color === "cyan" ? "shadow-[0_0_10px_#06b6d4]" : "shadow-[0_0_10px_#a855f7]";
  const bg = color === "cyan" ? "bg-cyan-500" : "bg-purple-500";

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="h-44 w-12 bg-[#08080a] border border-zinc-800 rounded shadow-inner relative flex justify-center py-2">
        <div className="absolute inset-y-2 left-2 w-1 flex flex-col justify-between py-1 opacity-20">
          {[...Array(9)].map((_, i) => <div key={i} className="h-[1px] w-full bg-white" />)}
