             {logs.map((log, i) => (
               <div key={i} className="text-[9px] flex gap-4">
                 <span className="text-zinc-800">[{new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}]</span>
