          <div className="col-span-3 flex flex-col gap-6">
            <div className="p-4 bg-black/60 border border-zinc-800 rounded-lg flex-1 flex flex-col">
               <div className="flex items-center gap-2 border-b border-zinc-800 pb-2 mb-6">
                 <Zap size={12} className="text-purple-500" />
                 <h3 className="text-[9px] font-black text-zinc-400 tracking-widest uppercase">CHANNEL_MIX</h3>
               </div>
               <div className="flex justify-between gap-2 h-full">
                 <ProFader label="KICK" value={levels.kick} level={meterLevels.kick} color="cyan" onChange={v => setLevels(s => ({...s, kick: v}))} />
                 <ProFader label="SNARE" value={levels.snare} level={meterLevels.snare} color="cyan" onChange={v => setLevels(s => ({...s, snare: v}))} />
                 <ProFader label="HATS" value={levels.hats} level={meterLevels.hats} color="purple" onChange={v => setLevels(s => ({...s, hats: v}))} />
                 <ProFader label="MASTER" value={levels.master} level={meterLevels.master} color="purple" onChange={v => setLevels(s => ({...s, master: v}))} />
               </div>
            </div>

            {error && (
              <div className="bg-red-500/10 border border-red-500/30 p-3 rounded flex items-center gap-2 animate-pulse">
                <AlertCircle size={14} className="text-red-500 flex-shrink-0" />
                <span className="text-[9px] text-red-400 mono uppercase truncate">{error}</span>
              </div>
            )}
          </div>
        </div>

        {/* BOTTOM CONSOLE */}
        <div className="relative z-10 px-16 h-24 bg-black border-t-2 border-zinc-800 flex items-center justify-between font-mono">
          <div className="space-y-1">
             {logs.map((log, i) => (
               <div key={i} className="text-[9px] flex gap-4">
                 <span className="text-zinc-800">[{new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}]</span>
                 <span className={log.includes('SUCCESS') || log.includes('READY') ? 'text-cyan-400' : log.includes('ERROR') ? 'text-red-500' : 'text-zinc-600'}>{log}</span>
               </div>
             ))}
          </div>
          <div className="flex items-center gap-12">
             <div className="flex flex-col items-end">
                <span className="text-[8px] text-zinc-600 uppercase tracking-tighter">ENGINE_LOAD</span>
                <span className={`text-xs font-bold tracking-widest ${stage === PipelineStage.ANALYZING ? 'text-red-500' : 'text-emerald-500'}`}>
                  {stage === PipelineStage.ANALYZING ? '98%' : '14%'} NOMINAL
                </span>
             </div>
             <div className="flex items-center gap-3">
                <div className="flex flex-col items-end">
                  <span className="text-[10px] text-white font-black italic">BUILDWHILE</span>
                  <span className="text-[8px] text-zinc-700">© 2025 NEURAL_OS</span>
                </div>
                <div className={`w-8 h-8 rounded-full border border-white/5 flex items-center justify-center ${isPlaying ? 'animate-spin-slow' : ''}`}>
                   <Disc size={16} className={isPlaying ? 'text-cyan-500' : 'text-zinc-800'} />
                </div>
             </div>
          </div>
        </div>

      </div>

      <style>{`
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 8s linear infinite;
        }
      `}</style>
    </div>
  );
}

// Utility class to encode AudioBuffer to WAV format
// This is needed because AudioBuffer cannot be directly converted to a base64 string
// and Gemini API expects audio data as base64.
class WAVEncoder {
  private sampleRate: number;
  private numChannels: number;
  private interleaved: Float32Array;

  constructor(audioData: Float32Array, sampleRate: number, numChannels: number = 1) {
    this.sampleRate = sampleRate;
    this.numChannels = numChannels;
    this.interleaved = audioData; // Assuming single channel for now
  }

  private writeString(view: DataView, offset: number, s: string): number {
    for (let i = 0; i < s.length; i++) {
      view.setUint8(offset + i, s.charCodeAt(i));
    }
    return offset + s.length;
  }

  private writeUint16(view: DataView, offset: number, value: number): number {
    view.setUint16(offset, value, true); // Little endian
    return offset + 2;
  }

  private writeUint32(view: DataView, offset: number, value: number): number {
    view.setUint32(offset, value, true); // Little endian
    return offset + 4;
  }

  public encode(): Blob {
    const dataLength = this.interleaved.length * 2; // 16-bit PCM
    const buffer = new ArrayBuffer(44 + dataLength);
    const view = new DataView(buffer);

    let offset = 0;

    // RIFF chunk
    offset = this.writeString(view, offset, 'RIFF');
    offset = this.writeUint32(view, offset, 36 + dataLength); // file size
    offset = this.writeString(view, offset, 'WAVE');

    // FMT chunk
    offset = this.writeString(view, offset, 'fmt ');
    offset = this.writeUint32(view, offset, 16); // chunk size
    offset = this.writeUint16(view, offset, 1); // audio format (1 = PCM)
    offset = this.writeUint16(view, offset, this.numChannels);
    offset = this.writeUint32(view, offset, this.sampleRate);
    offset = this.writeUint32(view, offset, this.sampleRate * this.numChannels * 2); // byte rate
    offset = this.writeUint16(view, offset, this.numChannels * 2); // block align
    offset = this.writeUint16(view, offset, 16); // bits per sample

    // DATA chunk
    offset = this.writeString(view, offset, 'data');
    offset = this.writeUint32(view, offset, dataLength);

    // Write PCM data
    for (let i = 0; i < this.interleaved.length; i++) {
      let s = Math.max(-1, Math.min(1, this.interleaved[i]));
      s = s < 0 ? s * 0x8000 : s * 0x7FFF; // Convert to 16-bit signed int
      view.setInt16(offset + i * 2, s, true); // Little endian
    }

    return new Blob([view], { type: 'audio/wav' });
  }
}

export interface MidiNote {
  pitch: number;
  startTime: number;
  duration: number;
  velocity: number;
  instrument?: string;
}

export interface TranscriptionResponse {
  notes: MidiNote[];
  bpm: number;
  timeSignature: string;
}

export enum PipelineStage {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  CONVERTING = 'CONVERTING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

